-- 1. 删除合伙人-城市关联记录
DELETE FROM partner_cities 
WHERE partnerId IN (
  SELECT id FROM partners WHERE phone IN ('13900000200', '13900000602', '13900000989')
);

-- 2. 删除合伙人记录
DELETE FROM partners 
WHERE phone IN ('13900000200', '13900000602', '13900000989');

-- 3. 删除用户账号
DELETE FROM users 
WHERE id IN (16020692, 16020693, 16020694, 16020710) 
   OR username IN ('13900000200', '13900000602', '13900000989');

